      {{select_gb_cols}}
      1 as id_dbtutils_test_fewer_rows_than,
      count(*) as count_our_model 
    from {{ model }}
    {{ groupby_gb_cols }}

),
b as (

    select 
      {{select_gb_cols}}
      1 as id_dbtutils_test_fewer_rows_than,
      count(*) as count_comparison_model 
    from {{ compare_model }}
    {{ groupby_gb_cols }}

),
