    {%- endset %}
    (
        -- to break ties when the amount is eaxtly at the bucket egde
        case
            when
                mod(
                    {{ dbt.safe_cast(expr, dbt.type_numeric() ) }},
                    {{ dbt.safe_cast(bin_size, dbt.type_numeric() ) }}
